// client/src/pages/AddProductPage.jsx
import React, { useState } from 'react';
import './AdminPage.css'; // Shared CSS for admin pages

const AddProductPage = () => {
    const [name, setName] = useState('');
    const [description, setDescription] = useState('');
    const [price, setPrice] = useState('');
    const [category, setCategory] = useState('');
    const [imageUrl, setImageUrl] = useState('');
    const [stock, setStock] = useState('');
    const [error, setError] = useState('');
    const [message, setMessage] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setMessage('');

        const productData = { name, description, price: parseFloat(price), category, imageUrl, stock: parseInt(stock) };

        try {
            // In a real app, you'd send a POST request to your backend /api/products (admin route)
            // const response = await fetch('/api/products', {
            //     method: 'POST',
            //     headers: {
            //         'Content-Type': 'application/json',
            //         'Authorization': `Bearer ${localStorage.getItem('token')}` // Send auth token
            //     },
            //     body: JSON.stringify(productData)
            // });
            // const data = await response.json();

            // if (!response.ok) {
            //     throw new Error(data.message || 'Failed to add product');
            // }

            setMessage('Product added successfully!');
            console.log('Product added:', productData);
            // Clear form
            setName('');
            setDescription('');
            setPrice('');
            setCategory('');
            setImageUrl('');
            setStock('');
        } catch (err) {
            setError(err.message || 'An error occurred while adding product.');
        }
    };

    return (
        <div className="admin-page container">
            <h1>Add New Product</h1>
            <div className="admin-form-card card">
                {error && <p className="error-message">{error}</p>}
                {message && <p className="success-message">{message}</p>}
                <form onSubmit={handleSubmit}>
                    <div className="form-group">
                        <label htmlFor="name">Product Name</label>
                        <input type="text" id="name" value={name} onChange={(e) => setName(e.target.value)} required />
                    </div>
                    <div className="form-group">
                        <label htmlFor="description">Description</label>
                        <textarea id="description" value={description} onChange={(e) => setDescription(e.target.value)} rows="4" required></textarea>
                    </div>
                    <div className="form-group">
                        <label htmlFor="price">Price ($)</label>
                        <input type="number" id="price" value={price} onChange={(e) => setPrice(e.target.value)} min="0" step="0.01" required />
                    </div>
                    <div className="form-group">
                        <label htmlFor="category">Category</label>
                        <input type="text" id="category" value={category} onChange={(e) => setCategory(e.target.value)} required />
                    </div>
                    <div className="form-group">
                        <label htmlFor="imageUrl">Image URL</label>
                        <input type="text" id="imageUrl" value={imageUrl} onChange={(e) => setImageUrl(e.target.value)} />
                    </div>
                    <div className="form-group">
                        <label htmlFor="stock">Stock Quantity</label>
                        <input type="number" id="stock" value={stock} onChange={(e) => setStock(e.target.value)} min="0" required />
                    </div>
                    <button type="submit" className="btn btn-primary admin-form-btn">Add Product</button>
                </form>
            </div>
        </div>
    );
};

export default AddProductPage;
